// ============================================================
// src/components/Lobby.jsx
// Handles: enter name → create/join room → waiting room
// ============================================================
import React, { useState, useEffect } from "react";
import axios from "axios";
import socket from "../socket";

const API = process.env.REACT_APP_BACKEND_URL || "http://localhost:5000";

export default function Lobby({ onGameStart }) {
  // ── State ─────────────────────────────────────────────────
  const [step, setStep]           = useState("name");   // name | choose | waiting
  const [playerName, setPlayerName] = useState("");
  const [player, setPlayer]       = useState(null);
  const [lobbyName, setLobbyName] = useState("");
  const [totalRounds, setTotalRounds] = useState(3);
  const [maxPlayers, setMaxPlayers]   = useState(8);
  const [joinCode, setJoinCode]   = useState("");
  const [game, setGame]           = useState(null);
  const [error, setError]         = useState("");
  const [loading, setLoading]     = useState(false);

  // ── Socket: live lobby updates ────────────────────────────
  useEffect(() => {
    socket.on("lobbyUpdated", (data) => {
      setGame(prev => prev ? { ...prev, players: data.players, totalRounds: data.totalRounds } : prev);
    });
    socket.on("roundStarted", (data) => {
      // Game has started — lift state up
      onGameStart(game, player);
    });
    return () => {
      socket.off("lobbyUpdated");
      socket.off("roundStarted");
    };
  }, [game, player, onGameStart]);

  // ── Handlers ──────────────────────────────────────────────
  const handleCreatePlayer = async () => {
    setError("");
    if (!playerName.trim()) return setError("Enter your name first.");
    setLoading(true);
    try {
      const { data } = await axios.post(`${API}/api/game/player`, { name: playerName.trim() });
      setPlayer(data.player);
      setStep("choose");
    } catch (e) { setError(e.response?.data?.error || "Error creating player"); }
    finally { setLoading(false); }
  };

  const handleCreateRoom = async () => {
    setError("");
    if (!lobbyName.trim()) return setError("Enter a room name.");
    setLoading(true);
    try {
      const { data } = await axios.post(`${API}/api/game/create`, {
        lobbyName: lobbyName.trim(), totalRounds, maxPlayers,
        playerId: player._id, playerName: player.name,
      });
      setGame(data.game);
      socket.emit("joinRoom", { code: data.game.code, playerId: player._id });
      setStep("waiting");
    } catch (e) { setError(e.response?.data?.error || "Error creating room"); }
    finally { setLoading(false); }
  };

  const handleJoinRoom = async () => {
    setError("");
    if (!joinCode.trim()) return setError("Enter a room code.");
    setLoading(true);
    try {
      const { data } = await axios.post(`${API}/api/game/join`, {
        code: joinCode.trim().toUpperCase(),
        playerId: player._id, playerName: player.name,
      });
      setGame(data.game);
      socket.emit("joinRoom", { code: data.game.code, playerId: player._id });
      setStep("waiting");
    } catch (e) { setError(e.response?.data?.error || "Room not found"); }
    finally { setLoading(false); }
  };

  const handleStartGame = () => {
    socket.emit("startGame", { code: game.code });
  };

  const isHost = game && player && game.hostId === player._id;

  // ── Render: name entry ────────────────────────────────────
  if (step === "name") return (
    <div className="screen">
      <div className="logo-wrap"><h1 className="logo">IMPOSTOR<span>·X</span></h1><p className="tagline">Find the impostor among you</p></div>
      <div className="card">
        <h2>What's your name?</h2>
        <input className="inp" placeholder="Enter nickname…" maxLength={20}
          value={playerName} onChange={e => setPlayerName(e.target.value)}
          onKeyDown={e => e.key === "Enter" && handleCreatePlayer()} />
        <button className="btn primary" onClick={handleCreatePlayer} disabled={loading}>
          {loading ? "…" : "Continue →"}
        </button>
        {error && <p className="err">{error}</p>}
      </div>
    </div>
  );

  // ── Render: create or join ────────────────────────────────
  if (step === "choose") return (
    <div className="screen">
      <div className="logo-wrap"><h1 className="logo">IMPOSTOR<span>·X</span></h1><p className="tagline">Hey, <strong>{player.name}</strong>!</p></div>
      <div className="two-col">
        <div className="card">
          <h2>Create Room</h2>
          <input className="inp" placeholder="Room name…" value={lobbyName}
            onChange={e => setLobbyName(e.target.value)} />
          <label className="lbl">Rounds: <strong>{totalRounds}</strong></label>
          <input type="range" className="slider" min={1} max={20} value={totalRounds}
            onChange={e => setTotalRounds(Number(e.target.value))} />
          <label className="lbl">Max players: <strong>{maxPlayers}</strong></label>
          <input type="range" className="slider" min={2} max={16} value={maxPlayers}
            onChange={e => setMaxPlayers(Number(e.target.value))} />
          <button className="btn primary" onClick={handleCreateRoom} disabled={loading}>
            {loading ? "…" : "Create Room"}
          </button>
        </div>
        <div className="card">
          <h2>Join Room</h2>
          <input className="inp code-inp" placeholder="ROOM CODE" maxLength={6}
            value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())}
            onKeyDown={e => e.key === "Enter" && handleJoinRoom()} />
          <button className="btn secondary" onClick={handleJoinRoom} disabled={loading}>
            {loading ? "…" : "Join Room →"}
          </button>
        </div>
      </div>
      {error && <p className="err center">{error}</p>}
    </div>
  );

  // ── Render: waiting room ──────────────────────────────────
  if (step === "waiting" && game) return (
    <div className="screen">
      <div className="logo-wrap"><h1 className="logo">IMPOSTOR<span>·X</span></h1></div>
      <div className="card wide">
        <div className="room-header">
          <div>
            <h2>{game.lobbyName}</h2>
            <p className="sub">Rounds: {game.totalRounds} &nbsp;|&nbsp; Max: {game.maxPlayers} players</p>
          </div>
          <div className="code-badge">
            <span className="clabel">ROOM CODE</span>
            <span className="ccode">{game.code}</span>
          </div>
        </div>

        <h3 className="section-lbl">Players <span className="count">{game.players?.length}</span></h3>
        <ul className="player-list">
          {(game.players || []).map(p => (
            <li key={p._id} className={p._id === player._id ? "me" : ""}>
              <span className="av">{p.name[0].toUpperCase()}</span>
              {p.name}
              {p._id === player._id && <span className="you">YOU</span>}
              {p._id === game.hostId  && <span className="host">HOST</span>}
            </li>
          ))}
        </ul>

        {isHost ? (
          <button className="btn start" onClick={handleStartGame}
            disabled={!game.players || game.players.length < 2}>
            ▶ Start Game
          </button>
        ) : (
          <p className="wait-msg">⏳ Waiting for host to start…</p>
        )}
        {error && <p className="err">{error}</p>}
      </div>
    </div>
  );

  return null;
}
